import React, { useState } from 'react';
import { MapPin, Mail, Phone, Facebook, Twitter, Instagram, Menu, X, Search, User } from 'lucide-react';

export default function MorviNavbar() {
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  return (
    <div className="w-full">
      {/* Top Bar - Orange */}
      <div className="bg-[#ff9c00] text-white py-3">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex flex-wrap items-center justify-between text-sm">
            {/* Left Side - Contact Info */}
            <div className="flex flex-wrap items-center gap-4 lg:gap-6">
              <div className="flex items-center gap-2">
                <MapPin className="w-4 h-4" />
                <span className="hidden sm:inline">Samudragarh Purba Burdwan west bengal</span>
              </div>
              <div className="flex items-center gap-2">
                <Mail className="w-4 h-4" />
                <span className="hidden md:inline">Email: morvicropscience@gmail.com</span>
              </div>
              <div className="flex items-center gap-2">
                <Phone className="w-4 h-4" />
                <span>Hotline Number: 7987279783</span>
              </div>
            </div>

            {/* Right Side - Social Media */}
            <div className="flex items-center gap-4">
              <span className="hidden sm:inline font-medium">Follow Us:</span>
              <div className="flex items-center gap-3">
                <a href="#" className="hover:scale-110 transition-transform">
                  <Facebook className="w-4 h-4" />
                </a>
                <a href="#" className="hover:scale-110 transition-transform">
                  <Twitter className="w-4 h-4" />
                </a>
                <a href="#" className="hover:scale-110 transition-transform">
                  <Instagram className="w-4 h-4" />
                </a>
                <a href="#" className="hover:scale-110 transition-transform">
                  <svg className="w-4 h-4" viewBox="0 0 24 24" fill="currentColor">
                    <path d="M12 0C5.373 0 0 5.373 0 12s5.373 12 12 12 12-5.373 12-12S18.627 0 12 0zm5.894 8.221l-1.97 9.28c-.145.658-.537.818-1.084.508l-3-2.21-1.446 1.394c-.14.18-.357.295-.6.295-.002 0-.003 0-.005 0l.213-3.054 5.56-5.022c.24-.213-.054-.334-.373-.121l-6.869 4.326-2.96-.924c-.64-.203-.654-.64.135-.954l11.566-4.458c.538-.196 1.006.128.832.941z"/>
                  </svg>
                </a>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Main Navigation Bar - White */}
      <nav className="bg-white shadow-md sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between h-20">
            {/* Logo */}
            <div className="flex items-center space-x-3">
              <div className="relative">
                {/* Circular logo with leaf */}
                <div className="w-16 h-16 rounded-full border-4 border-green-600 flex items-center justify-center bg-white relative">
                  <div className="text-green-600 font-bold text-sm">MCS</div>
                  {/* Small leaf decorations */}
                  <div className="absolute -top-1 -right-1 w-6 h-6 bg-green-600 rounded-full flex items-center justify-center">
                    <div className="w-3 h-3 bg-white rounded-full"></div>
                  </div>
                </div>
              </div>
              <div>
                <h1 className="text-xl font-bold text-gray-900">MORVI CROP SCIENCE PVT LTD</h1>
                <p className="text-xs text-gray-600">Agricultural Excellence</p>
              </div>
            </div>

            {/* Desktop Navigation */}
            <div className="hidden lg:flex items-center space-x-8">
              <a href="#home" className="text-green-600 font-semibold border-b-2 border-green-600 pb-1">
                Home
              </a>
              <a href="/about" className="text-gray-700 hover:text-green-600 font-medium transition-colors">
                About Us
              </a>
              <div className="relative group">
                <button className="text-gray-700 hover:text-green-600 font-medium transition-colors flex items-center gap-1">
                  Product Details
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                  </svg>
                </button>
              </div>
              <a href="#contact" className="text-gray-700 hover:text-green-600 font-medium transition-colors">
                Contact
              </a>
            </div>

            {/* Right Side Icons & Button */}
            <div className="hidden lg:flex items-center space-x-4">
              <button className="p-2 hover:bg-gray-100 rounded-full transition-colors">
                <Search className="w-5 h-5 text-gray-700" />
              </button>
              <button className="p-2 hover:bg-gray-100 rounded-full transition-colors">
                <User className="w-5 h-5 text-gray-700" />
              </button>
              <button className="bg-green-600 hover:bg-green-700 text-white px-6 py-3 rounded-lg font-semibold transition-all transform hover:scale-105 shadow-md">
                Get A Quote
              </button>
            </div>

            {/* Mobile Menu Button */}
            <button 
              className="lg:hidden p-2 rounded-md hover:bg-gray-100"
              onClick={() => setIsMenuOpen(!isMenuOpen)}
            >
              {isMenuOpen ? (
                <X className="w-6 h-6 text-gray-700" />
              ) : (
                <Menu className="w-6 h-6 text-gray-700" />
              )}
            </button>
          </div>

          {/* Mobile Menu */}
          {isMenuOpen && (
            <div className="lg:hidden py-4 border-t border-gray-200">
              <div className="flex flex-col space-y-4">
                <a href="#home" className="text-green-600 font-semibold px-4 py-2 bg-green-50 rounded-lg">
                  Home
                </a>
                <a href="#about" className="text-gray-700 hover:text-green-600 font-medium px-4 py-2 hover:bg-gray-50 rounded-lg transition-colors">
                  About Us
                </a>
                <a href="#products" className="text-gray-700 hover:text-green-600 font-medium px-4 py-2 hover:bg-gray-50 rounded-lg transition-colors">
                  Product Details
                </a>
                <a href="#contact" className="text-gray-700 hover:text-green-600 font-medium px-4 py-2 hover:bg-gray-50 rounded-lg transition-colors">
                  Contact
                </a>
                <div className="flex items-center space-x-4 px-4 pt-4 border-t border-gray-200">
                  <button className="p-2 hover:bg-gray-100 rounded-full transition-colors">
                    <Search className="w-5 h-5 text-gray-700" />
                  </button>
                  <button className="p-2 hover:bg-gray-100 rounded-full transition-colors">
                    <User className="w-5 h-5 text-gray-700" />
                  </button>
                  <button className="bg-green-600 hover:bg-green-700 text-white px-6 py-3 rounded-lg font-semibold flex-1">
                    Get A Quote
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      </nav>
    </div>
  );
}       